const fs = require('fs');
const path = require('path');

// Lista de pastas para escanear - ADICIONE MAIS PASTAS AQUI
const folders = [
  'C:\\Users\\LuizFerreira\\Desktop\\ProjSitesAI',
  'C:\\Users\\LuizFerreira\\Documents\\Projects',
  'C:\\Users\\LuizFerreira\\GitHub',
  'D:\\VibeCoding\\ProjSitesAI',
  'D:\\Projects'
];

const allProjects = [];

for (const basePath of folders) {
  if (!fs.existsSync(basePath)) continue;

  try {
    const dirs = fs.readdirSync(basePath, { withFileTypes: true });

    for (const dir of dirs) {
      if (!dir.isDirectory()) continue;
      const projectPath = path.join(basePath, dir.name);

      let type = 'unknown';
      if (fs.existsSync(path.join(projectPath, 'package.json'))) type = 'nodejs';
      else if (fs.existsSync(path.join(projectPath, 'composer.json'))) type = 'php';
      else if (fs.existsSync(path.join(projectPath, 'wp-config.php'))) type = 'wordpress';
      else if (fs.existsSync(path.join(projectPath, 'requirements.txt'))) type = 'python';
      else if (fs.existsSync(path.join(projectPath, 'go.mod'))) type = 'go';
      else if (fs.existsSync(path.join(projectPath, 'Cargo.toml'))) type = 'rust';

      if (type !== 'unknown') {
        allProjects.push({
          name: dir.name,
          path: projectPath,
          type: type,
          baseFolder: basePath
        });
      }
    }
  } catch (e) {}
}

return [{ json: { projects: allProjects } }];
